import {useEffect, useMemo, useState} from "react";
import {Link} from "react-router-dom";
import api from "../api";

/* ---------- helpers ---------- */
const VND = (v) => Number(v || 0).toLocaleString("vi-VN");
const fmtDate = (s) => (s ? new Date(s).toLocaleDateString("vi-VN") : "-");

const STATUS_COLORS = {
    NEW: "bg-sky-100 text-sky-700",
    PENDING: "bg-amber-100 text-amber-700",
    APPROVING: "bg-indigo-100 text-indigo-700",
    IN_PROGRESS: "bg-blue-100 text-blue-700",
    COMPLETED: "bg-emerald-100 text-emerald-700",
    CANCELLED: "bg-rose-100 text-rose-700",
};

const STATUS_OPTS = [
    { value: "", label: "Tất cả" },
    { value: "NEW", label: "Mới" },
    { value: "PENDING", label: "Chờ duyệt" },
    { value: "APPROVING", label: "Đang duyệt" },
    { value: "IN_PROGRESS", label: "Đang thực hiện" },
    { value: "COMPLETED", label: "Hoàn tất" },
    { value: "CANCELLED", label: "Hủy" },
];

const TYPE_OPTS = [
    { value: "", label: "Tất cả" },
    { value: "CONSTRUCTION", label: "Thi công" },
    { value: "SERVICE", label: "Dịch vụ" },
    { value: "SUPPLY", label: "Cung cấp" },
];

function useDebounce(v, delay = 450) {
    const [val, setVal] = useState(v);
    useEffect(() => { const t = setTimeout(() => setVal(v), delay); return () => clearTimeout(t); }, [v, delay]);
    return val;
}

/* ---------- page ---------- */
export default function Contracts() {
    // filters
    const [q, setQ] = useState("");
    const dq = useDebounce(q);
    const [status, setStatus] = useState("");
    const [type, setType] = useState("");
    const [from, setFrom] = useState("");
    const [to, setTo] = useState("");

    // data
    const [rows, setRows] = useState([]);
    const [page, setPage] = useState(0);
    const [pages, setPages] = useState(1);
    const [loading, setLoading] = useState(true);

    // view controls
    const [viewMode, setViewMode] = useState("cards"); // 'cards' | 'list'
    const [cardSize, setCardSize] = useState("md"); // 'lg' | 'md' | 'sm'

    // appendix modal
    const [appendixOpen, setAppendixOpen] = useState(false);
    const [appendixSaving, setAppendixSaving] = useState(false);
    const [appendixContract, setAppendixContract] = useState(null);
    const [appendixForm, setAppendixForm] = useState({ title: "", note: "" });

    useEffect(() => { load(); /* eslint-disable-next-line */ }, [page, dq, status, type, from, to]);

    async function load() {
        setLoading(true);
        try {
            const { data } = await api.get("/api/contracts", {
                params: {
                    q: dq || undefined,
                    status: status || undefined,
                    type: type || undefined,
                    from: from || undefined,
                    to: to || undefined,
                    page, size: 12, sort: "id,desc",
                },
            });
            const list = Array.isArray(data) ? data : data?.content || [];
            const totalPages = Array.isArray(data) ? 1 : (data?.totalPages || 1);
            setRows(list);
            setPages(totalPages);
        } catch (e) {
            console.error(e);
            setRows([]); setPages(1);
        } finally {
            setLoading(false);
        }
    }

    const gridCols = useMemo(() => {
        if (cardSize === "lg") return "grid-cols-1 xl:grid-cols-2";
        if (cardSize === "sm") return "grid-cols-1 md:grid-cols-2 xl:grid-cols-3 2xl:grid-cols-4";
        return "grid-cols-1 md:grid-cols-2 xl:grid-cols-2 2xl:grid-cols-3";
    }, [cardSize]);
    const cardPad = cardSize === "lg" ? "p-6" : cardSize === "sm" ? "p-4" : "p-5";

    function openAppendix(c) {
        setAppendixContract(c);
        setAppendixForm({ title: "", note: "" });
        setAppendixOpen(true);
    }

    async function saveAppendix(e) {
        e.preventDefault();
        if (!appendixContract?.id) return;
        setAppendixSaving(true);
        try {
            await api.post(`/api/contracts/${appendixContract.id}/appendices`, {
                title: appendixForm.title?.trim(),
                note: appendixForm.note?.trim() || null,
            });
            setAppendixOpen(false);
            // có thể reload chi tiết trong trang detail; ở list chưa cần gọi lại
            alert("Đã tạo phụ lục cho hợp đồng");
        } catch (err) {
            alert(err?.response?.data?.message || "Tạo phụ lục thất bại (cần API /contracts/{id}/appendices)");
        } finally {
            setAppendixSaving(false);
        }
    }

    function StatusBadge({ value }) {
        const cls = STATUS_COLORS[value] || "bg-slate-100 text-slate-700";
        const label = STATUS_OPTS.find(s => s.value === value)?.label || value || "-";
        return <span className={`px-2 py-0.5 rounded-full text-xs ${cls}`}>{label}</span>;
    }

    /* ---------- views ---------- */
    const Toolbar = (
        <div className="flex flex-col md:flex-row md:items-end md:justify-between gap-3 mb-2">
            <div>
                <h2 className="text-lg font-semibold">Hợp đồng</h2>
                <p className="text-sm text-slate-500">Tìm kiếm, lọc và quản lý hợp đồng</p>
            </div>

            <div className="flex flex-wrap items-end gap-2">
                <div className="flex flex-col">
                    <label className="text-xs text-slate-500 mb-1">Tìm kiếm</label>
                    <input
                        className="w-80 px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                        placeholder="Mã/tiêu đề/KH/NVKD…"
                        value={q}
                        onChange={(e) => { setQ(e.target.value); setPage(0); }}
                    />
                </div>

                <div className="flex flex-col">
                    <label className="text-xs text-slate-500 mb-1">Loại HĐ</label>
                    <select
                        className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                        value={type}
                        onChange={(e) => { setType(e.target.value); setPage(0); }}
                    >
                        {TYPE_OPTS.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
                    </select>
                </div>

                <div className="flex flex-col">
                    <label className="text-xs text-slate-500 mb-1">Trạng thái</label>
                    <select
                        className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                        value={status}
                        onChange={(e) => { setStatus(e.target.value); setPage(0); }}
                    >
                        {STATUS_OPTS.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
                    </select>
                </div>

                <div className="flex flex-col">
                    <label className="text-xs text-slate-500 mb-1">Từ ngày</label>
                    <input type="date" className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                           value={from} onChange={(e)=>{ setFrom(e.target.value); setPage(0); }}/>
                </div>
                <div className="flex flex-col">
                    <label className="text-xs text-slate-500 mb-1">Đến ngày</label>
                    <input type="date" className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                           value={to} onChange={(e)=>{ setTo(e.target.value); setPage(0); }}/>
                </div>

                {/* view controls */}
                <div className="flex flex-col">
                    <label className="text-xs text-slate-500 mb-1">Hiển thị</label>
                    <div className="flex gap-2">
                        <select
                            className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                            value={viewMode}
                            onChange={(e) => setViewMode(e.target.value)}
                            title="Chọn kiểu hiển thị"
                        >
                            <option value="cards">Cards</option>
                            <option value="list">List</option>
                        </select>
                        <select
                            className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                            value={cardSize}
                            onChange={(e) => setCardSize(e.target.value)}
                            title="Độ rộng thẻ"
                        >
                            <option value="lg">Rộng</option>
                            <option value="md">Vừa</option>
                            <option value="sm">Gọn</option>
                        </select>
                    </div>
                </div>

                <Link
                    to="/contracts/new"
                    className="ml-auto px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700"
                >
                    Thêm hợp đồng
                </Link>
            </div>
        </div>
    );

    const Cards = (
        <div className={`grid ${gridCols} gap-4`}>
            {loading ? (
                <div className="col-span-full bg-white rounded-2xl border border-indigo-100 shadow p-6">Đang tải…</div>
            ) : rows.length === 0 ? (
                <div className="col-span-full bg-white rounded-2xl border border-indigo-100 shadow p-6">Chưa có dữ liệu</div>
            ) : rows.map((c) => {
                const code = c.contractCode || c.code || `HD-${c.id}`;
                const cus = c.customer?.name || c.customerName || "-";
                const sales = c.sales?.fullName || c.salesName || "-";
                const typeLabel = TYPE_OPTS.find(t => t.value === c.contractType)?.label || c.contractType || "-";
                const isDone = String(c.status).toUpperCase() === "COMPLETED";

                return (
                    <div key={c.id} className={`bg-white rounded-2xl border border-indigo-100 shadow ${cardPad}`}>
                        <div className="flex items-start justify-between gap-3">
                            <div>
                                <div className="text-base font-semibold">{code}</div>
                                <div className="text-sm text-slate-600">{c.title || "-"}</div>
                                <div className="text-xs text-slate-500 mt-1">
                                    Loại: {typeLabel} • KH: {cus} • Sales: {sales}
                                </div>
                                <div className="text-xs text-slate-500">
                                    Ngày ký: {fmtDate(c.signedDate)} {c.note ? `• Ghi chú: ${c.note}` : ""}
                                </div>
                            </div>
                            <StatusBadge value={c.status}/>
                        </div>

                        <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4">
                            <div className="rounded-xl bg-slate-50 p-3">
                                <div className="text-xs text-slate-500">Giá trị</div>
                                <div className="font-semibold tabular-nums">{VND(c.totalAmount)} đ</div>
                            </div>
                            <div className="rounded-xl bg-slate-50 p-3">
                                <div className="text-xs text-slate-500">Đã thu</div>
                                <div className="font-semibold tabular-nums">{VND(c.paidAmount)} đ</div>
                            </div>
                            <div className="rounded-xl bg-slate-50 p-3">
                                <div className="text-xs text-slate-500">Còn lại</div>
                                <div className="font-semibold tabular-nums">
                                    {VND(c.remainingAmount ?? Math.max(0, (c.totalAmount||0) - (c.paidAmount||0)))} đ
                                </div>
                            </div>
                        </div>

                        <div className="flex items-center gap-2 mt-4">
                            {isDone ? (
                                <>
                                    <Link
                                        to={`/contracts/${c.id}`}
                                        className="px-3 py-1.5 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700"
                                        title="Xem chi tiết hợp đồng"
                                    >
                                        Xem chi tiết
                                    </Link>
                                    <button
                                        onClick={() => openAppendix(c)}
                                        className="px-3 py-1.5 rounded-lg bg-emerald-50 text-emerald-700 hover:bg-emerald-100"
                                        title="Tạo phụ lục cho hợp đồng này"
                                    >
                                        Tạo phụ lục
                                    </button>
                                </>
                            ) : (
                                <>
                                    <Link
                                        to={`/contracts/${c.id}/edit`}
                                        className="px-3 py-1.5 rounded-lg bg-slate-100 hover:bg-slate-200"
                                    >
                                        Sửa
                                    </Link>
                                    <Link
                                        to={`/contracts/${c.id}/delete`}
                                        className="px-3 py-1.5 rounded-lg bg-rose-50 text-rose-700 hover:bg-rose-100"
                                    >
                                        Xóa
                                    </Link>
                                </>
                            )}
                        </div>
                    </div>
                );
            })}
        </div>
    );

    const List = (
        <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
            <div className="overflow-auto">
                <table className="min-w-full text-sm">
                    <thead className="bg-indigo-50 text-slate-600">
                    <tr>
                        <th className="px-4 py-3 text-left">Mã HĐ</th>
                        <th className="px-4 py-3 text-left">Tiêu đề</th>
                        <th className="px-4 py-3 text-left">KH</th>
                        <th className="px-4 py-3 text-left">Sales</th>
                        <th className="px-4 py-3 text-left">Loại</th>
                        <th className="px-4 py-3 text-left">Ngày ký</th>
                        <th className="px-4 py-3 text-left">Trạng thái</th>
                        <th className="px-4 py-3 text-left">Giá trị</th>
                        <th className="px-4 py-3 text-left">Đã thu</th>
                        <th className="px-4 py-3 text-left">Còn lại</th>
                        <th className="px-4 py-3 text-right">Thao tác</th>
                    </tr>
                    </thead>
                    <tbody className="divide-y">
                    {loading ? (
                        <tr><td className="px-4 py-6" colSpan={11}>Đang tải…</td></tr>
                    ) : rows.length === 0 ? (
                        <tr><td className="px-4 py-6" colSpan={11}>Chưa có dữ liệu</td></tr>
                    ) : rows.map(c => {
                        const code = c.contractCode || c.code || `HD-${c.id}`;
                        const cus = c.customer?.name || c.customerName || "-";
                        const sales = c.sales?.fullName || c.salesName || "-";
                        const typeLabel = TYPE_OPTS.find(t => t.value === c.contractType)?.label || c.contractType || "-";
                        const remain = c.remainingAmount ?? Math.max(0, (c.totalAmount||0) - (c.paidAmount||0));
                        const isDone = String(c.status).toUpperCase() === "COMPLETED";
                        return (
                            <tr key={c.id} className="hover:bg-indigo-50/40">
                                <td className="px-4 py-3 font-medium">{code}</td>
                                <td className="px-4 py-3">{c.title || "-"}</td>
                                <td className="px-4 py-3">{cus}</td>
                                <td className="px-4 py-3">{sales}</td>
                                <td className="px-4 py-3">{typeLabel}</td>
                                <td className="px-4 py-3">{fmtDate(c.signedDate)}</td>
                                <td className="px-4 py-3"><StatusBadge value={c.status}/></td>
                                <td className="px-4 py-3 tabular-nums">{VND(c.totalAmount)} đ</td>
                                <td className="px-4 py-3 tabular-nums">{VND(c.paidAmount)} đ</td>
                                <td className="px-4 py-3 tabular-nums">{VND(remain)} đ</td>
                                <td className="px-4 py-3">
                                    <div className="flex justify-end gap-2">
                                        {isDone ? (
                                            <>
                                                <Link to={`/contracts/${c.id}`}
                                                      className="px-2 py-1 rounded bg-indigo-600 text-white hover:bg-indigo-700">
                                                    Xem
                                                </Link>
                                                <button
                                                    onClick={() => openAppendix(c)}
                                                    className="px-2 py-1 rounded bg-emerald-50 text-emerald-700 hover:bg-emerald-100">
                                                    Phụ lục
                                                </button>
                                            </>
                                        ) : (
                                            <>
                                                <Link to={`/contracts/${c.id}/edit`}
                                                      className="px-2 py-1 rounded bg-slate-100 hover:bg-slate-200">Sửa</Link>
                                                <Link to={`/contracts/${c.id}/delete`}
                                                      className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100">Xóa</Link>
                                            </>
                                        )}
                                    </div>
                                </td>
                            </tr>
                        );
                    })}
                    </tbody>
                </table>
            </div>
        </div>
    );

    return (
        <div className="space-y-4">
            {Toolbar}

            {viewMode === "cards" ? Cards : List}

            {/* pagination */}
            <div className="flex gap-2">
                <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                        onClick={() => setPage(p => Math.max(0, p - 1))} disabled={page <= 0}>← Trước</button>
                <div className="px-3 py-1.5 text-sm">Trang {page + 1}/{pages}</div>
                <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                        onClick={() => setPage(p => p + 1)} disabled={page + 1 >= pages}>Sau →</button>
            </div>

            {/* Appendix modal */}
            {appendixOpen && appendixContract && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-xl bg-white rounded-2xl shadow-xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">Tạo phụ lục – {appendixContract.contractCode || `HD-${appendixContract.id}`}</div>
                            <button className="text-slate-500 hover:text-slate-700" onClick={() => setAppendixOpen(false)}>Đóng</button>
                        </div>
                        <form onSubmit={saveAppendix} className="p-5 space-y-3">
                            <div>
                                <label className="text-sm text-slate-600">Tiêu đề phụ lục</label>
                                <input
                                    required
                                    value={appendixForm.title}
                                    onChange={(e)=>setAppendixForm(f=>({...f,title:e.target.value}))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Ghi chú</label>
                                <textarea
                                    rows={3}
                                    value={appendixForm.note}
                                    onChange={(e)=>setAppendixForm(f=>({...f,note:e.target.value}))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>
                            <div className="flex items-center justify-end gap-2 pt-1">
                                <button type="button" className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200"
                                        onClick={()=>setAppendixOpen(false)} disabled={appendixSaving}>Hủy</button>
                                <button className="px-3 py-2 rounded-lg bg-emerald-600 text-white hover:bg-emerald-700 disabled:opacity-50"
                                        disabled={appendixSaving}>{appendixSaving ? "Đang lưu…" : "Tạo phụ lục"}</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
